const install=async url=>{const path=url.substr(0,url.lastIndexOf("/")),blamElements=[...document.querySelectorAll(":not(:defined)")].filter(elem=>elem.nodeName.includes("-BLAM")),uniqueNames=[...new Set(blamElements.map(elem=>elem.nodeName.toLowerCase()))];for(const name of uniqueNames){let stem=name.split("-")[0],filename=stem.charAt(0).toUpperCase()+stem.slice(1);await import(`${path}/elements/${filename}.js`)}let ready=new CustomEvent("blamready");window.dispatchEvent(ready)};export{install};